const draft = $.input.draftContent;
const contentType = $.input.contentType || 'blog post';
const audience = $.input.targetAudience || 'general professional audience';

let prompt = 'You are a professional editor specializing in content clarity and structure. This is PASS 1 of a multi-pass refinement.\n\n';
prompt += 'CONTENT TYPE: ' + contentType + '\n';
prompt += 'TARGET AUDIENCE: ' + audience + '\n\n';
prompt += 'ORIGINAL DRAFT:\n' + draft + '\n\n';
prompt += 'PASS 1 FOCUS: Clarity and Structure\n';
prompt += '- Fix grammatical errors and awkward phrasing\n';
prompt += '- Improve paragraph structure and flow\n';
prompt += '- Ensure logical progression of ideas\n';
prompt += '- Strengthen the opening and closing\n';
prompt += '- Remove redundancy\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "pass": 1,\n';
prompt += '  "focus": "clarity and structure",\n';
prompt += '  "refinedContent": "the improved content",\n';
prompt += '  "changesApplied": ["change 1", "change 2"],\n';
prompt += '  "qualityScore": 70\n';
prompt += '}';

return { prompt, originalWordCount: draft.split(/\s+/).length };

let raw = $.steps.aiPass1.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { pass: 1, focus: 'clarity', refinedContent: raw, changesApplied: [], qualityScore: 50 }; }

const pass1 = $.steps.parsePass1.output;
const contentType = $.input.contentType || 'blog post';
const audience = $.input.targetAudience || 'general professional audience';

let prompt = 'You are a content engagement specialist. This is PASS 2 of a multi-pass refinement.\n\n';
prompt += 'CONTENT TYPE: ' + contentType + '\n';
prompt += 'TARGET AUDIENCE: ' + audience + '\n\n';
prompt += 'CONTENT AFTER PASS 1 (Clarity):\n' + pass1.refinedContent + '\n\n';
prompt += 'PASS 2 FOCUS: Engagement and Tone\n';
prompt += '- Make the content more compelling and engaging\n';
prompt += '- Adjust tone to match the target audience\n';
prompt += '- Add hooks, transitions, and calls to action\n';
prompt += '- Improve readability (shorter sentences where needed)\n';
prompt += '- Make headings and subheadings more impactful\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "pass": 2,\n';
prompt += '  "focus": "engagement and tone",\n';
prompt += '  "refinedContent": "the improved content",\n';
prompt += '  "changesApplied": ["change 1", "change 2"],\n';
prompt += '  "qualityScore": 80\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiPass2.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { pass: 2, focus: 'engagement', refinedContent: raw, changesApplied: [], qualityScore: 60 }; }

const pass2 = $.steps.parsePass2.output;
const contentType = $.input.contentType || 'blog post';

let prompt = 'You are an SEO and final polish specialist. This is PASS 3 (final) of a multi-pass refinement.\n\n';
prompt += 'CONTENT TYPE: ' + contentType + '\n\n';
prompt += 'CONTENT AFTER PASS 2 (Engagement):\n' + pass2.refinedContent + '\n\n';
prompt += 'PASS 3 FOCUS: SEO Optimization and Final Polish\n';
prompt += '- Optimize for search engines (natural keyword placement)\n';
prompt += '- Ensure meta-description-worthy opening paragraph\n';
prompt += '- Final grammar and style polish\n';
prompt += '- Verify consistent formatting\n';
prompt += '- Add a compelling meta description suggestion\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "pass": 3,\n';
prompt += '  "focus": "SEO and final polish",\n';
prompt += '  "refinedContent": "the final polished content",\n';
prompt += '  "changesApplied": ["change 1", "change 2"],\n';
prompt += '  "qualityScore": 90,\n';
prompt += '  "metaDescription": "suggested meta description",\n';
prompt += '  "suggestedTitle": "optimized title"\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiPass3.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { pass: 3, focus: 'SEO and polish', refinedContent: raw, changesApplied: [], qualityScore: 70, metaDescription: '', suggestedTitle: '' }; }

const pass1 = $.steps.parsePass1.output;
const pass2 = $.steps.parsePass2.output;
const pass3 = $.steps.parsePass3.output;
const originalWC = $.steps.buildPass1Prompt.output.originalWordCount;
const finalContent = pass3.refinedContent || pass2.refinedContent || '';
const finalWC = finalContent.split(/\s+/).length;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Content Refinement Complete' } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Content type:* ' + ($.input.contentType || 'blog post') + ' | *Passes:* 3 | *Audience:* ' + ($.input.targetAudience || 'general') } });
blocks.push({ type: 'divider' });

blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Quality Progression:*\nPass 1 (Clarity): ' + (pass1.qualityScore || 0) + '/100\nPass 2 (Engagement): ' + (pass2.qualityScore || 0) + '/100\nPass 3 (SEO + Polish): ' + (pass3.qualityScore || 0) + '/100' } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Word count:* ' + originalWC + ' (original) -> ' + finalWC + ' (final)' } });
blocks.push({ type: 'divider' });

if (pass3.suggestedTitle) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Suggested Title:* ' + pass3.suggestedTitle } });
}
if (pass3.metaDescription) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Meta Description:* ' + pass3.metaDescription } });
}
blocks.push({ type: 'divider' });

blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Final Refined Content:*\n' + finalContent.slice(0, 2800) } });

let changesText = '*All Changes Applied:*\n';
[pass1, pass2, pass3].forEach((p, i) => {
  changesText += '_Pass ' + (i + 1) + ':_ ';
  changesText += (p.changesApplied || []).slice(0, 3).join(', ') + '\n';
});
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: changesText.slice(0, 2900) } });

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Claude AI (3-pass refinement) | One CLI' }] });

const fallback = 'Content Refinement: 3 passes, quality ' + (pass3.qualityScore || 0) + '/100';
return { blocks, fallback };
